 1	import React from 'react';
 2	import { EmptyState, EmptyStateBody, EmptyStateIcon, EmptyStateVariant, Title } from '@patternfly/react-core';
 3	import CubesIcon from '@patternfly/react-icons/dist/esm/icons/cubes-icon';
 4	
 5	export interface NoDataEmptyStateProps {
 6	  title: string;
 7	  description?: string;
 8	}
 9	
10	export const NoDataEmptyState: React.FC<NoDataEmptyStateProps> = ({ title, description }) => (
11	  <EmptyState variant={EmptyStateVariant.sm}>
12	    <EmptyStateIcon icon={CubesIcon} />
13	    <Title headingLevel="h2" size="lg">
14	      {title}
15	    </Title>
16	    {description && <EmptyStateBody>{description}</EmptyStateBody>}
17	  </EmptyState>
18	);

